+
+    auto_import_if_stale(
+        &mut storage_ctx.storage,
+        &storage_ctx.paths.beads_dir,
+        &storage_ctx.paths.jsonl_path,
+        Some(expected_prefix.as_str()),
+        allow_external_jsonl,
+        cli.allow_stale.unwrap_or(false),
+        no_auto_import,
+    )
